import React from 'react';
import type { DefaultSizeType } from '../../util';
import { Space } from '../../space';
import { Radio } from '../../radio';
import '../../space/style';
import '../../radio/style';

export interface SizeChangeProps {
  size: DefaultSizeType;
  onChange: (size: DefaultSizeType) => void;
}
export const SizeChange = Object.assign(
  (props: SizeChangeProps) => {
    const { size, onChange } = props;
    return (
      <Space>
        <span>尺寸：</span>
        <Radio.Group value={size} onChange={e => onChange(e as DefaultSizeType)}>
          <Radio.Button value="large">大</Radio.Button>
          <Radio.Button value="medium">中</Radio.Button>
          <Radio.Button value="small">小</Radio.Button>
        </Radio.Group>
      </Space>
    );
  },
  {
    useState: (s: DefaultSizeType = 'medium') => {
      const [size, setSize] = React.useState<DefaultSizeType>(s);
      const onChange = (sizeData: DefaultSizeType) => setSize(sizeData);
      return {
        size,
        onChange,
      };
    },
  },
);
